import React from 'react';

const PanelControls = ({
  onResetLayout,
  onMaximizeSidebar,
  onMaximizeEditor,
  onMaximizePreview,
  onToggleSidebar,
  onToggleEditor,
  sidebarWidth,
  editorWidth
}) => {
  return (
    <div className="panel-controls">
      <div className="panel-controls__group">
        <button
          className="panel-controls__btn"
          onClick={onResetLayout}
          title="Reset Layout"
        >
          <span className="panel-controls__icon">Reset</span>
        </button>
      </div>

      <div className="panel-controls__group">
        <button
          className={`panel-controls__btn ${sidebarWidth === 0 ? 'panel-controls__btn--collapsed' : ''}`}
          onClick={onToggleSidebar}
          title={sidebarWidth === 0 ? 'Show Sidebar' : 'Hide Sidebar'}
        >
          <span className="panel-controls__icon">Sidebar</span>
        </button>
        <button
          className={`panel-controls__btn ${editorWidth === 0 ? 'panel-controls__btn--collapsed' : ''}`}
          onClick={onToggleEditor}
          title={editorWidth === 0 ? 'Show Editor' : 'Hide Editor'}
        >
          <span className="panel-controls__icon">Editor</span>
        </button>
      </div>

      <div className="panel-controls__group">
        <button
          className="panel-controls__btn"
          onClick={onMaximizeSidebar}
          title="Maximize Sidebar"
        >
          <span className="panel-controls__icon">Max Sidebar</span>
        </button>
        <button
          className="panel-controls__btn"
          onClick={onMaximizeEditor}
          title="Maximize Editor"
        >
          <span className="panel-controls__icon">Max Editor</span>
        </button>
        <button
          className="panel-controls__btn"
          onClick={onMaximizePreview}
          title="Maximize Preview"
        >
          <span className="panel-controls__icon">Max Preview</span>
        </button>
      </div>
    </div>
  );
};

export default PanelControls;
